// Walk the MIME part tree and return ONE ITEM PER PDF found.
// Handles: nested multipart, top-level single-part PDF, deduplication.

function findPdfParts(parts, found) {
  if (!parts) return;
  for (const part of parts) {
    const mime = (part.mimeType || '').toLowerCase();
    const fname = (part.filename || '').toLowerCase();
    if (mime === 'application/pdf' || fname.endsWith('.pdf')) {
      found.push(part);
    } else {
      findPdfParts(part.parts, found);
    }
  }
}

const msg = $json;
const pdfParts = [];

if (msg.payload) {
  const topMime = (msg.payload.mimeType || '').toLowerCase();
  const topFname = (msg.payload.filename || '').toLowerCase();
  if (topMime === 'application/pdf' || topFname.endsWith('.pdf')) {
    // Single-part message — the payload itself is the PDF
    pdfParts.push(msg.payload);
  } else {
    findPdfParts(msg.payload.parts, pdfParts);
  }
}

// Deduplicate: some mailers embed the same PDF as both inline and attachment
const seen = new Set();
const unique = pdfParts.filter(part => {
  const key = (part.body && (part.body.attachmentId || part.body.data)) || '';
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

if (unique.length === 0) {
  return [{ json: { messageId: msg.id, found: false, attachmentId: null, inlineData: null } }];
}

return unique.map(part => {
  const body = part.body || {};
  return {
    json: {
      messageId: msg.id,
      found: true,
      attachmentId: body.attachmentId || null,
      inlineData: body.data || null,
      filename: part.filename || 'ticket.pdf',
      mimeType: part.mimeType || 'application/pdf',
    }
  };
});

// runOnceForEachItem: runs once per fetched PDF so $('Needs Fetch?').item
// correctly tracks the filename/mimeType for THIS specific PDF.

const pdfInfo = $('Needs Fetch?').item.json;
const base64url = ($input.item.json.data || '').trim();
if (!base64url) {
  throw new Error('Fetch Attachment Data returned no bytes — check Gmail OAuth2 scope includes gmail.readonly');
}

// Normalise base64url → standard base64, restore missing padding
const b64 = base64url.replace(/-/g, '+').replace(/_/g, '/');
const padded = b64 + '='.repeat((4 - b64.length % 4) % 4);

return [{
  json: { messageId: pdfInfo.messageId },
  binary: {
    file: {
      data: padded,
      mimeType: pdfInfo.mimeType || 'application/pdf',
      fileName: pdfInfo.filename || 'ticket.pdf',
    }
  },
}];

// Small PDFs: body.data is present inline in the full-message response.
const pdfInfo = $input.item.json;
const base64url = (pdfInfo.inlineData || '').trim();
if (!base64url) {
  throw new Error('Expected inline attachment data but body.data was empty');
}

// Normalise base64url → standard base64, restore missing padding
const b64 = base64url.replace(/-/g, '+').replace(/_/g, '/');
const padded = b64 + '='.repeat((4 - b64.length % 4) % 4);

return [{
  json: { messageId: pdfInfo.messageId },
  binary: {
    file: {
      data: padded,
      mimeType: pdfInfo.mimeType || 'application/pdf',
      fileName: pdfInfo.filename || 'ticket.pdf',
    }
  },
}];
